class Solution:
    def maxNumberOfBalloons(self, text):
        avail = {}
        for c in text:
            avail[c] = avail.get(c, 0) + 1
        count = 0
        while True:
            for c in 'balloon':
                if avail.get(c, 0) <= 0:
                    return count
                avail[c] -= 1
            count += 1

