var maxNumberOfBalloons = function(text) {
    const cnt = {};
    for (const c of text) cnt[c] = (cnt[c] || 0) + 1;
    const need = {};
    for (const c of 'balloon') need[c] = (need[c] || 0) + 1;
    let ans = Infinity;
    for (const c in need) ans = Math.min(ans, Math.floor((cnt[c] || 0) / need[c]));
